const { Manifold, label, setCircularSegments } = api;
setCircularSegments(32);

function box(min, max) {
  const s = [max[0] - min[0], max[1] - min[1], max[2] - min[2]];
  const c = [(min[0] + max[0]) / 2, (min[1] + max[1]) / 2, (min[2] + max[2]) / 2];
  return Manifold.cube(s, true).translate(c);
}

// Body: 16w x 26h x 5d, front face at y=-2.5
const body = box([-8, -2.5, -13], [8, 2.5, 13]);

// Protrusions — all go from y=-3 (front) to y=-1 (1.5 units into body)
const Yf = -3.0;
const Yb = -1.0;

// Screen bezel
const bezel = box([-5.5, Yf, 2.0], [5.5, Yb, 11.5]);

// Screen inside bezel
const screen = box([-4.5, Yf - 0.1, 2.8], [4.5, Yb, 10.8]);

// D-pad: horizontal + vertical bars (wider union piece)
const dpadH = box([-7.5, Yf, -5.5], [-3.5, Yb, -3.8]);
const dpadV = box([-6.25, Yf, -6.8], [-4.75, Yb, -2.5]);

// Action buttons: use rectangular bumps that clearly overlap body
const btnA = box([4.5, Yf, -5.0], [6.5, Yb, -3.0]);
const btnB = box([2.8, Yf, -6.8], [4.8, Yb, -4.8]);

// Start / Select
const startBtn = box([-1.8, Yf, -8.2], [-0.5, Yb, -7.5]);
const selectBtn = box([0.2, Yf, -8.2], [1.5, Yb, -7.5]);

// Speaker grille: 4 horizontal lines — made thick enough to union
const sp1 = box([3.0, Yf, -8.8], [7.5, Yb, -8.3]);
const sp2 = box([3.0, Yf, -9.5], [7.5, Yb, -9.0]);
const sp3 = box([3.0, Yf, -10.2], [7.5, Yb, -9.7]);
const sp4 = box([3.0, Yf, -10.9], [7.5, Yb, -10.4]);

// Build the full geometry as one Manifold union (no labels = 1 component)
const allFeatures = bezel.add(screen).add(dpadH).add(dpadV)
  .add(btnA).add(btnB)
  .add(startBtn).add(selectBtn)
  .add(sp1).add(sp2).add(sp3).add(sp4);

const fullBody = label(body.add(allFeatures), 'body');

// Now label specific surface regions by re-creating labeled overlapping shapes
// The labeled shapes overlap the full mesh — paintByLabels resolves by triangle provenance
const bezelL = label(bezel, 'bezel');
const screenL = label(screen, 'screen');
const dpadL = label(dpadH.add(dpadV), 'dpad');
const btnL = label(btnA.add(btnB), 'buttons');
const ssL = label(startBtn.add(selectBtn), 'startselect');
const spL = label(sp1.add(sp2).add(sp3).add(sp4), 'speaker');

return fullBody.add(bezelL).add(screenL).add(dpadL).add(btnL).add(ssL).add(spL);
